//! Geometric realization of the spectre tiling.
//!
//! Every hexagon of the marked-hexagon system corresponds to one actual
//! 14-sided spectre tile — except Γ, which carries two (the "mystic" pair;
//! the second one is the rare odd-orientation spectre).  There is no linear
//! map from hex-grid positions to spectre positions: geometry is propagated
//! tile-to-tile by gluing, walking the combinatorial structure.
//!
//! The transition tables come from Simon Tatham's puzzle collection
//! (`spectre-tables-auto.h`, generated by his `spectre-gen.c`), whose
//! conventions provably match ours: his child layout, child types and child
//! orientations per supertile equal `SUPERTILE_CHILDREN` exactly, so his
//! per-type base orientations coincide with ours and his hexagon edge `j`
//! is our direction `(j + 2) % 6` in the hexagon's base frame, uniformly.
//!
//! Vertices live in ℤ[d], d = exp(iπ/6), so all coordinates are exact.

use crate::hex::{DIRECTIONS, Hex};

/// Point of the plane as an integer combination of {1, d, d², d³} where
/// d = exp(iπ/6) (a 30° rotation); d⁴ = d² − 1.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Default)]
pub struct Zd(pub [i32; 4]);

impl Zd {
    pub const ZERO: Zd = Zd([0, 0, 0, 0]);
    pub const ONE: Zd = Zd([1, 0, 0, 0]);

    /// Multiply by d (rotate 30° counterclockwise).
    fn mul_d(self) -> Zd {
        let [a, b, c, e] = self.0;
        Zd([-e, a, b + e, c])
    }

    /// Rotate by `s` steps of 30° counterclockwise.
    pub fn rot30(self, s: i32) -> Zd {
        let mut r = self;
        for _ in 0..s.rem_euclid(12) {
            r = r.mul_d();
        }
        r
    }

    /// Cartesian coordinates, y pointing up.
    pub fn to_xy(self) -> (f64, f64) {
        let [a, b, c, e] = self.0;
        let h = 3f64.sqrt() / 2.0;
        (
            a as f64 + b as f64 * h + c as f64 * 0.5,
            e as f64 + b as f64 * 0.5 + c as f64 * h,
        )
    }
}

impl std::ops::Add for Zd {
    type Output = Zd;
    fn add(self, rhs: Zd) -> Zd {
        Zd(std::array::from_fn(|i| self.0[i] + rhs.0[i]))
    }
}

impl std::ops::Sub for Zd {
    type Output = Zd;
    fn sub(self, rhs: Zd) -> Zd {
        Zd(std::array::from_fn(|i| self.0[i] - rhs.0[i]))
    }
}

/// Turn at each spectre vertex, in 30° steps (Tatham's `spectre_angles`).
/// All 14 edges are unit length; the sum is −12, i.e. one clockwise turn.
const SPECTRE_ANGLES: [i32; 14] = [-3, -2, 3, -2, -3, 2, -3, 2, -3, -2, 0, -2, 3, -2];

/// All 14 vertices of a spectre, given vertices `u` and `v` of its edge
/// `index_of_u` (edge `i` runs from vertex `i` to vertex `i + 1`).  The
/// shape is rigid, so one edge determines the rest.
pub fn spectre_place(u: Zd, v: Zd, index_of_u: usize) -> [Zd; 14] {
    let mut verts = [Zd::ZERO; 14];
    let mut p = u;
    let mut disp = v - u;
    for i in 0..14 {
        verts[(i + index_of_u) % 14] = p;
        p = p + disp;
        disp = disp.rot30(SPECTRE_ANGLES[(i + 1 + index_of_u) % 14]);
    }
    verts
}

/// Ear-clip triangulation of the (concave) spectre by vertex index — valid
/// for every rigid placement, since the tiling never mirrors the tile.
pub const SPECTRE_TRIANGLES: [[usize; 3]; 12] = [
    [13, 0, 1],
    [13, 1, 2],
    [2, 3, 4],
    [13, 2, 4],
    [13, 4, 5],
    [13, 5, 6],
    [7, 8, 9],
    [7, 9, 10],
    [6, 7, 10],
    [6, 10, 11],
    [6, 11, 12],
    [6, 12, 13],
];

/// Number of spectres a hexagon of type `t` carries.
pub fn num_spectres(t: u8) -> u8 {
    if t == 0 { 2 } else { 1 }
}

/// One cell of the spectre transition maps (Tatham's `struct MapEntry`).
///
/// In `SPECMAP` (keyed by the spectre edge being crossed): if `internal`,
/// the move stays within the same hexagon — `hi` is the destination spectre
/// index and `lo` its entry edge (only happens inside Γ's pair).  Otherwise
/// the move leaves the hexagon by its edge `hi` (Tatham numbering: our base
/// direction `(hi + 2) % 6`) at position `lo` within that edge's boundary
/// segment.
///
/// In `SPECIN` (keyed by boundary position, via `SPECEDGES`): if `internal`,
/// entering here lands on edge `lo` of spectre `hi`.  Otherwise the entry
/// point is on the Σ spur and bounces straight back out by hexagon edge `hi`
/// at position `lo`.
#[derive(Debug, Clone, Copy)]
pub struct MapEntry {
    pub internal: bool,
    pub hi: u8,
    pub lo: u8,
}

/// Boundary segment of one hexagon edge: `len` spectre edges starting at
/// `start` in the type's `SPECIN` table, in boundary-walk order.  Two glued
/// hexagon edges traverse the shared segment in opposite orders.
#[derive(Debug, Clone, Copy)]
pub struct MapEdge {
    pub start: u8,
    pub len: u8,
}

const fn m(internal: bool, hi: u8, lo: u8) -> MapEntry {
    MapEntry { internal, hi, lo }
}

const fn e(start: u8, len: u8) -> MapEdge {
    MapEdge { start, len }
}

