/// `SPECMAP[t][14 * spectre_index + spectre_edge]` — what crossing that
/// spectre edge does, for a type-`t` hexagon in its base orientation.
pub const SPECMAP: [&[MapEntry]; 9] = [
    &SPECMAP_G, &SPECMAP_D, &SPECMAP_J, &SPECMAP_L, &SPECMAP_X, &SPECMAP_P, &SPECMAP_S, &SPECMAP_F,
    &SPECMAP_Y,
];

/// `SPECEDGES[t][j]` — boundary segment of hexagon edge `j` (Tatham
/// numbering) of a type-`t` hexagon.
#[rustfmt::skip]
pub const SPECEDGES: [&[MapEdge; 6]; 9] = [
    &SPECEDGES_G, &SPECEDGES_D, &SPECEDGES_J, &SPECEDGES_L, &SPECEDGES_X, &SPECEDGES_P,
    &SPECEDGES_S, &SPECEDGES_F, &SPECEDGES_Y,
];

/// `SPECIN[t]` — entry table indexed via [`SPECEDGES`].
pub const SPECIN: [&[MapEntry]; 9] = [
    &SPECIN_G, &SPECIN_D, &SPECIN_J, &SPECIN_L, &SPECIN_X, &SPECIN_P, &SPECIN_S, &SPECIN_F,
    &SPECIN_Y,
];

/// Tatham's hexagon edge number for our base-frame direction `delta`.
pub fn tatham_edge(delta: usize) -> usize {
    (delta + 4) % 6
}

/// Our base-frame direction for Tatham's hexagon edge number `j`.
pub fn our_direction(j: usize) -> usize {
    (j + 2) % 6
}

/// Cross edge `edge` of spectre `index` of the hexagon at `hex` (whose
/// `(type, world rotation)` is `start`).  `tile_at(from, w)` must give the
/// `(type, world rotation)` of the hexagon at `from + DIRECTIONS[w]`, or
/// `None` outside the patch.  Returns the destination spectre as
/// `(hexagon, spectre index, entry edge)`; `None` when the move leaves the
/// patch.  Mirrors Tatham's `spectrectx_step`, with our transducer-driven
/// hexagon adjacency in place of his hexagon coordinate algorithm.
pub fn spectre_step(
    mut hex: Hex,
    start: (u8, u8),
    index: u8,
    edge: u8,
    tile_at: &mut dyn FnMut(Hex, usize) -> Option<(u8, u8)>,
) -> Option<(Hex, u8, u8)> {
    let (t, mut rot) = start;
    let mut m = SPECMAP[t as usize][14 * index as usize + edge as usize];
    while !m.internal {
        // Leave this hexagon by edge m.hi (own base frame) — world
        // direction w — and re-enter the neighbor's boundary segment at the
        // reversed position.  A non-internal entry there is the Σ spur:
        // bounce straight out again.
        let w = (our_direction(m.hi as usize) + rot as usize) % 6;
        let (t2, rot2) = tile_at(hex, w)?;
        hex = hex + DIRECTIONS[w];
        let back = (w + 9 - rot2 as usize) % 6;
        let me = SPECEDGES[t2 as usize][tatham_edge(back)];
        m = SPECIN[t2 as usize][(me.start + me.len - 1 - m.lo) as usize];
        rot = rot2;
    }
    Some((hex, m.hi, m.lo))
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::tree_coords::{canonical_patch_paths, edge_adjacency, path_rotation, types_along};
    use std::collections::{HashMap, VecDeque};

    /// The outline closes, all 14 edges are unit length, and every vertex
    /// angle is the prescribed multiple of 30°.
    #[test]
    fn outline_is_closed_unit_14_gon() {
        let v = spectre_place(Zd::ZERO, Zd::ONE, 0);
        for i in 0..14 {
            let (ax, ay) = v[i].to_xy();
            let (bx, by) = v[(i + 1) % 14].to_xy();
            let len2 = (bx - ax).powi(2) + (by - ay).powi(2);
            assert!((len2 - 1.0).abs() < 1e-9, "edge {i} not unit");
        }
        // Placing from any other edge of the same two vertices reproduces a
        // rotation of the same shape (sanity of the index_of_u walk).
        for k in 0..14 {
            let w = spectre_place(v[k], v[(k + 1) % 14], k);
            assert_eq!(w, v, "re-placing from edge {k} changed the polygon");
        }
    }

    /// Glued hexagon edges must carry equally many spectre boundary edges.
    /// The pairing comes from the marked-tile edge adjacency, the lengths
    /// from Tatham's tables — agreement pins the convention translation.
    #[test]
    fn segment_lengths_match_edge_adjacency() {
        for (&(t1, d1), partners) in edge_adjacency() {
            for &(t2, d2) in partners {
                let l1 = SPECEDGES[t1 as usize][tatham_edge(d1 as usize)].len;
                let l2 = SPECEDGES[t2 as usize][tatham_edge(d2 as usize)].len;
                assert_eq!(
                    l1, l2,
                    "boundary length mismatch: ({t1},{d1}) [{l1}] ~ ({t2},{d2}) [{l2}]",
                );
            }
        }
    }

    /// Generate all spectres of a canonical patch by BFS gluing and check
    /// global consistency: every spectre reached by several routes gets the
    /// same placement, every step reciprocates, and the count is one
    /// spectre per hexagon plus one extra per Γ.
    fn check_patch_spectres(top: u8, depth: usize) {
        let (_, paths) = canonical_patch_paths(top, depth);
        let tiles: HashMap<Hex, (u8, u8)> = paths
            .iter()
            .map(|(&h, c)| {
                let t = *types_along(top, &c.path).last().unwrap();
                (h, (t, path_rotation(top, &c.path)))
            })
            .collect();
        let mut tile_at = |from: Hex, w: usize| tiles.get(&(from + DIRECTIONS[w])).copied();

        let seed = Hex::new(0, 0);
        let mut placed: HashMap<(Hex, u8), [Zd; 14]> = HashMap::new();
        placed.insert((seed, 0), spectre_place(Zd::ZERO, Zd::ONE, 0));
        let mut queue = VecDeque::from([(seed, 0u8)]);
        while let Some((hex, idx)) = queue.pop_front() {
            let poly = placed[&(hex, idx)];
            let start = tiles[&hex];
            for edge in 0..14u8 {
                let Some((h2, i2, e2)) = spectre_step(hex, start, idx, edge, &mut tile_at) else {
                    continue;
                };
                // Reciprocity: stepping back returns here across `edge`.
                assert_eq!(
                    spectre_step(h2, tiles[&h2], i2, e2, &mut tile_at),
                    Some((hex, idx, edge)),
                    "top {top}: not reciprocal from {hex:?}#{idx} edge {edge}",
                );
                let p2 = spectre_place(
                    poly[(edge as usize + 1) % 14],
                    poly[edge as usize],
                    e2 as usize,
                );
                match placed.get(&(h2, i2)) {
                    Some(prev) => {
                        assert_eq!(*prev, p2, "top {top}: conflicting placement of {h2:?}#{i2}",)
                    }
                    None => {
                        placed.insert((h2, i2), p2);
                        queue.push_back((h2, i2));
                    }
                }
            }
        }

        let expected: usize = tiles.values().map(|&(t, _)| num_spectres(t) as usize).sum();
        assert_eq!(placed.len(), expected, "top {top} depth {depth}: count");
    }

    #[test]
    fn patch_spectres_consistent_depth_2_all_tops() {
        for top in 0..9 {
            check_patch_spectres(top, 2);
        }
    }

    #[test]
    fn patch_spectres_consistent_depth_3_gamma_sigma() {
        check_patch_spectres(0, 3);
        check_patch_spectres(6, 3);
    }
}
